     * decimal point shown, zero-padded to the total digit count. Matches this
     * legacy binary's DISPLAY of PIC 9(..)V99 fields (lines 29-30), which emits
     * the point between the integer and fractional digits.
     */
    private static String formatNumeric(BigDecimal value, int digits, int scale) {
        int intDigits = digits - scale;
        BigInteger unscaled = value.abs().unscaledValue();
        String s = unscaled.toString();
        if (s.length() > digits) {
            s = s.substring(s.length() - digits);
        }
        StringBuilder sb = new StringBuilder();
        while (sb.length() + s.length() < digits) {
            sb.append('0');
        }
        sb.append(s);
        String full = sb.toString(); // exactly `digits` characters
        String intPart = full.substring(0, intDigits);
        String fracPart = full.substring(intDigits);
        if (scale == 0) {
            return intPart;
        }
        return intPart + "." + fracPart;
    }

    private static String spaces(int n) {
        return " ".repeat(n);
    }
